import{_ as a,o as n,c as s,ag as t}from"./chunks/framework.BDReElpY.js";const f=JSON.parse('{"title":"Raw Pointers and FFI","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/unsafe.md","filePath":"archive/reference/unsafe.md"}'),i={name:"archive/reference/unsafe.md"};function l(p,e,o,r,c,d){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="raw-pointers-and-ffi" tabindex="-1">Raw Pointers and FFI <a class="header-anchor" href="#raw-pointers-and-ffi" aria-label="Permalink to &quot;Raw Pointers and FFI&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>Vex provides zero-cost interoperability with C and low-level memory access via <code>unsafe</code> blocks.</p><hr><h2 id="_1-safety-boundary-unsafe" tabindex="-1">1. Safety Boundary (<code>unsafe</code>) <a class="header-anchor" href="#_1-safety-boundary-unsafe" aria-label="Permalink to &quot;1. Safety Boundary (\`unsafe\`)&quot;">​</a></h2><p>Operations that cannot be verified by the borrow checker must be wrapped in <code>unsafe</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>unsafe {</span></span>
<span class="line"><span>    let ptr = malloc(1024);</span></span>
<span class="line"><span>    free(ptr);</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Unsafe Operations:</strong></p><ul><li>Dereferencing raw pointers.</li><li>Calling <code>extern</code> functions (FFI).</li><li>Accessing unions.</li><li>Implementing <code>unsafe</code> contracts.</li></ul><hr><h2 id="_2-raw-pointers" tabindex="-1">2. Raw Pointers <a class="header-anchor" href="#_2-raw-pointers" aria-label="Permalink to &quot;2. Raw Pointers&quot;">​</a></h2><p>Vex distinguishes between safe References (<code>&amp;T</code>) and raw Pointers (<code>*T</code>).</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>*T</code></td><td style="text-align:left;">Raw immutable pointer (C <code>const T*</code>).</td></tr><tr><td style="text-align:left;"><code>*T!</code></td><td style="text-align:left;">Raw mutable pointer (C <code>T*</code>).</td></tr><tr><td style="text-align:left;"><code>&amp;T</code></td><td style="text-align:left;">Safe immutable reference (Borrowed).</td></tr><tr><td style="text-align:left;"><code>&amp;T!</code></td><td style="text-align:left;">Safe mutable reference (Exclusive).</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = 10;</span></span>
<span class="line"><span>let ptr: *i32! = &amp;raw x; // Create raw pointer</span></span>
<span class="line"><span></span></span>
<span class="line"><span>unsafe {</span></span>
<span class="line"><span>    *ptr = 20;</span><span> // Dereference requires unsafe</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_3-foreign-function-interface-ffi" tabindex="-1">3. Foreign Function Interface (FFI) <a class="header-anchor" href="#_3-foreign-function-interface-ffi" aria-label="Permalink to &quot;3. Foreign Function Interface (FFI)&quot;">​</a></h2><p>Call C libraries directly.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Declaration</span></span>
<span class="line"><span>extern &quot;C&quot; {</span></span>
<span class="line"><span>    fn malloc(size: usize): *void;</span></span>
<span class="line"><span>    fn free(ptr: *void);</span></span>
<span class="line"><span>    fn printf(fmt: *u8, ...): i32;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Usage</span></span>
<span class="line"><span>fn main() {</span></span>
<span class="line"><span>    unsafe {</span></span>
<span class="line"><span>        let ptr = malloc(32);</span></span>
<span class="line"><span>        free(ptr);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="calling-convention" tabindex="-1">Calling Convention <a class="header-anchor" href="#calling-convention" aria-label="Permalink to &quot;Calling Convention&quot;">​</a></h3><ul><li><code>extern &quot;C&quot;</code>: Standard C ABI.</li><li><code>extern &quot;system&quot;</code>: System call ABI (e.g. <code>stdcall</code> on Windows).</li></ul><hr><h2 id="_4-native-modules-vxc" tabindex="-1">4. Native Modules (<code>.vxc</code>) <a class="header-anchor" href="#_4-native-modules-vxc" aria-label="Permalink to &quot;4. Native Modules (\`.vxc\`)&quot;">​</a></h2><p>For complex C integration, Vex uses <code>.vxc</code> files (Vex C headers). These allow inline C code or direct linking.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// math.vxc</span></span>
<span class="line"><span>extern &quot;C&quot; {</span></span>
<span class="line"><span>    fn cos(x: f64): f64;</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,24)])])}const h=a(i,[["render",l]]);export{f as __pageData,h as default};
